using System.Text.Json;
using System.Text.Json.Serialization;
using System.Text.Json.Serialization.Metadata;

// Set up options with a default resolver (source-gen context for Person only)
var options = new JsonSerializerOptions
{
    TypeInfoResolver = AppJsonContext.Default
};

// 1) Strongly-typed retrieval: GetTypeInfo<T>() returns JsonTypeInfo<T> directly
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"Got typed metadata for Person – Kind: {personInfo.Kind}");

// 2) Probe without throwing: TryGetTypeInfo returns false if metadata isn't available
bool found = options.TryGetTypeInfo(typeof(UnknownThing), out JsonTypeInfo? info);
Console.WriteLine($"TryGetTypeInfo for UnknownThing: found={found}, info={info?.Type?.Name ?? "(null)"}");

// Also show the success path of TryGetTypeInfo
bool found2 = options.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? info2);
Console.WriteLine($"TryGetTypeInfo for Person: found={found2}, info={info2?.Type?.Name ?? "(null)"}");

// Types
public record Person(string Name, int Age);
public record UnknownThing(string X);

// Source-gen context that only knows about Person
[JsonSerializable(typeof(Person))]
public partial class AppJsonContext : JsonSerializerContext;

